    15→
    16→type CurrencyValue = number | undefined | string;
    17→
    18→type CashBackTransactions = PropsItemsTransactions & {
    19→  percentage: number;
    20→  cashback: string;
    21→  resgate: boolean;
    22→};
    23→
    24→export const formatToCurrency = (fullValue: CurrencyValue): string => {
    25→  if (typeof fullValue === 'undefined') return `R$ 0,00`;
    26→
    27→  const [value, cents] = String(fullValue).replace('-', '').split('.');
    28→
    29→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    30→  let formattedValue = '';
    31→
    32→  for (let i = 0; i < value.length; i += 1) {
    33→    const currentDigit = value[value.length - 1 - i];
    34→
    35→    if (i > 0 && i % 3 === 0) {
    36→      formattedValue = `${currentDigit}.${formattedValue}`;
    37→    } else {
    38→      formattedValue = `${currentDigit}${formattedValue}`;
    39→    }
    40→  }
    41→
    42→  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]}${
    43→    formattedCents[1]
    44→  }`;
    45→};
    46→
    47→export const formatToNumericCurrency = (fullValue: CurrencyValue, decimalPlaces = 2): string => {
    48→  if (typeof fullValue === 'undefined' || fullValue === '0')
    49→    return `0,${'0'.repeat(decimalPlaces)}`;
    50→
    51→  const [value, cents] = String(fullValue).replace('-', '').split('.');
    52→
    53→  const formattedCents = cents ? cents.padEnd(decimalPlaces, '0') : '0'.repeat(decimalPlaces);
    54→  let formattedValue = '';
    55→
    56→  for (let i = 0; i < value.length; i += 1) {
    57→    const currentDigit = value[value.length - 1 - i];
    58→
    59→    if (i > 0 && i % 3 === 0) {
    60→      formattedValue = `${currentDigit}.${formattedValue}`;
    61→    } else {
    62→      formattedValue = `${currentDigit}${formattedValue}`;
    63→    }
    64→  }
    65→
    66→  return `${formattedValue},${formattedCents.slice(0, decimalPlaces)}`;
    67→};
    68→
    69→export const formatToInternationalCurrency = (
    70→  moneyType: string,
    71→  fullValue: number | undefined | string
    72→): string => {
    73→  if (typeof fullValue === 'undefined') return `${moneyType} 0,00`;
    74→
    75→  const [value, cents] = String(fullValue).replace('-', '').split(',');
    76→
    77→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
    78→  let formattedValue = '';
