import { CustomerTypes } from '@semparar/mf-app-user';
import { Benefit } from '../redux/ducks/offers';
import { Alert, Linking } from 'react-native';

export const delay = (delay: number) => {
  return new Promise(res => setTimeout(res, delay));
};

export type AccountType =
  | 'isPostPaid'
  | 'isTrigger'
  | 'isPrePaid'
  | 'isPrePaidManual'
  | 'isAccountCreditCard'
  | 'isCreditCard';

export const getAccountType = (customer: typeof CustomerTypes) => {
  const {
    isPostPaid,
    isPrePaid,
    isPrePaidManual,
    isTrigger,
    isAccountCreditCard,
  } = customer;

  const types = {
    isPostPaid,
    isPrePaid,
    isPrePaidManual,
    isTrigger,
    isAccountCreditCard,
  };
  const accountType = Object.entries(types).find(type => type[1] === true);
  if (accountType) return accountType[0] as AccountType;
};

export const hasBenefits = (
  benefits: Record<string, Benefit> | null | undefined | Benefit[],
): boolean => {
  return benefits != null && Object.keys(benefits).length > 0;
};

export const formatToCurrency = (
  fullValue: number | undefined | string,
): string => {
  if (typeof fullValue === 'undefined') return `R$ 0,00`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]
    }${formattedCents[1]}`;
};

export function isValidZip({
  neighborhood,
  city,
  address,
  state,
}: {
  neighborhood: string;
  city: string;
  address: string;
  state: string;
}): boolean {
  return state !== '' && (neighborhood !== '' || city !== '' || address !== '');
}

export function sendWhatsMessage(number: string, message: string) {
  const url = `whatsapp://send?phone=${number}&text=${encodeURIComponent(message)}`

  Linking.canOpenURL(url)
    .then(supported => {
      if (!supported) {
        Alert.alert('Erro', 'O WhatsApp não está instalado no dispositivo.');
      } else {
        return Linking.openURL(url);
      }
    })
    .catch(err => console.error('Erro ao abrir o WhatsApp:', err));
}

export const dayName = (day: number) => {
  const days = [
    'Domingo',
    'Segunda Feira',
    'Terça Feira',
    'Quarta Feira',
    'Quinta Feira',
    'Sexta Feira',
    'Sábado',
  ];

  return days[day] || days[0];
};

