export const getParsedCurrency = (text: string) => {
  const digits = (text || '').replace(/\D/g, '');
  const n = parseInt(digits, 10);
  if (Number.isNaN(n)) {
    return 0;
  }
  return n / 100;
};

export const getParsePoints = (text: string) => {
  const digits = (text || '').replace(/\D/g, '');
  const n = parseInt(digits, 10);
  return Number.isNaN(n) ? 0 : n;
};
```

**Purpose:**
- `getParsedCurrency`: Extracts digits from text and converts to decimal currency (dividing by 100 for cents)
- `getParsePoints`: Extracts and parses integer values from text strings

